var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>A-17 구역, D-03 구역 통신 두절!</color>","JPN":"<color=#ffd34c>A-17区域、D-03区域からの通信が途絶！</color>","ENG":"<color=#ffd34c>Areas A-17 and D-03, communication lost!</color>","TWN":"<color=#ffd34c>A-17區域，D-03區域通訊中斷！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>보관 중인 아티팩트는 전부 소각해!</color>","JPN":"<color=#ffd34c>保管しているアーティファクトは全部焼却しろ！</color>","ENG":"<color=#ffd34c>Burn all the Artifacts we have on board!</color>","TWN":"<color=#ffd34c>保管中的人造神器全部燒毀！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오, 오지 마! 오지 마아아아!</color>","JPN":"<color=#ffd34c>く、来るな！　来るなあああ！</color>","ENG":"<color=#ffd34c>S-stay back! GET AWAAAAY!</color>","TWN":"<color=#ffd34c>別…別過來！別過來啊啊！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>그림자들의 정신 공격에 대응할 수가 없습니다! 카운터들까지 아군을…… 커헉!</color>","JPN":"<color=#ffd34c>シャドウの精神攻撃に対応できません！　カウンターまで味方を……がはっ！</color>","ENG":"<color=#ffd34c>There is nothing we can do about the Shadows' psychological attacks! Even the Counters are attacking our– Kuh!!</color>","TWN":"<color=#ffd34c>對付不了暗影的精神攻擊！連制裁者都在殘殺我方……咳啊！</color>"},"stage":{"bg":"BLACK","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"……기관장님과 통신 연결하도록.","JPN":"……機関長へ通信を繋げろ。","ENG":"...Connect me to Chief.","TWN":"……聯絡機關長。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"으, 으으……","JPN":"う、うう……","ENG":"U-ugh...","TWN":"呃…呃呃……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"명령이 안 들리나! 기관장님과 연결해! 어서!","JPN":"命令が聞こえないのか！　機関長だ！　早く！","ENG":"Did you not hear me?! Connect me to Chief, NOW!","TWN":"沒聽見我的命令嗎！聯絡機關長！快點！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"아, 알겠습니다!!","JPN":"りょ、了解しました！！","ENG":"Y-yes, sir!!","TWN":"好…好的！！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"기다리고 있었어요. 전략 위성을 통해 상황은 파악했습니다.","JPN":"待っていましたわ。戦略衛星を通じて状況は把握しています。","ENG":"I've been waiting for you to call. I saw what happened through the satellite.","TWN":"我正在等你的電話。情況我已經通過戰略衛星了解到了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_BEEP"},{"id":"L16_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"죄송합니다, 기관장님. 저희의 예상 이상으로 적의 전력이 우위에 있었습니다.","JPN":"申し訳ございません、機関長。我々の予想以上に、敵の戦力が優勢でした。","ENG":"My apologies, Chief. The enemy forces were far superior to our expectations.","TWN":"對不起，機關長。敵人的戰鬥力超出了我們的預料。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"네. 최선을 다했다는 사실은 저도 알고 있답니다.","JPN":"はい。全力で戦ったということは私も知っています。","ENG":"Yes, and I know you did your best.","TWN":"是的，我也知道你們已經盡力了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"사실대로 말씀드리죠. 저희 전력으로는 모든 봉인 시설을 완벽하게 방어할 수 없습니다.","JPN":"ありのままにお話ししましょう。私たちの戦力では、すべての隔離施設を完璧に防御することはできません。","ENG":"I'll be honest with you. With our limited resources, we are unable to fully defend all quarantine facilities.","TWN":"說實話，憑我們的戰鬥力，根本沒辦法守住所有隔離設施。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"어느 정도는 각오했던 상황이었어요.","JPN":"ある程度は覚悟していた状況です。","ENG":"This much, I had expected.","TWN":"在某種程度上，我已經做好了心理準備。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"당신도 함께 퇴거하라고 지시한들…… 명령에 따르지 않겠죠.","JPN":"あなたに一緒に退却するよう指示しても……命令に従わないでしょう。","ENG":"But even if I had ordered you to retreat, I'm sure you would have refused.","TWN":"就算我下令讓你一起撤退……你應該也不會聽吧。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"가출했으니 모른 척 해 달라는 지시만 안 내리셨어도 고민했을 텐데 말입니다.","JPN":"家出をしたから知らないふりをしてくれ、というご指示さえなければ悩んではみたはずですが。","ENG":"I would've considered it if you hadn't ordered me to turn a blind eye to your running away from home.","TWN":"如果你沒下達“我離家出走了，你就假裝不知道”的指示，我應該會很苦惱。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"저 광신도들에게 무덤을 만들어 줄 기회입니다. 놓칠 수 없죠.","JPN":"あの狂信徒たちに墓を作ってやるチャンスです。逃すわけにはいきません。","ENG":"I cannot let this chance to bury those fanatics pass me by.","TWN":"這是給那些狂信徒挖墳墓的機會，我是不會錯過的。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"ELIZABETH_PRYDWEN_NULL_NULL","text":{"KOREA":"알겠습니다. 마지막까지 무운을 빌도록 하죠.","JPN":"わかりました。最後までご武運をお祈りします。","ENG":"Understood. Then I wish you the best of luck.","TWN":"知道了，那祝你好運。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"후우……","JPN":"ふぅ……","ENG":"*Sigh*","TWN":"呼……"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"시설 책임자로서 전파한다. 전 기관원들에게 교전을 중단하고 퇴각할 것을 알리도록.","JPN":"施設の責任者として伝える。全機関員、交戦を中断し退却するように。","ENG":"Attention all agents, this is the head of facility. All personnel shall cease fire and retreat.","TWN":"我是設施負責人，傳達我的命令，全體機關成員停止交戰，準備撤退。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"현 시간부로 LAKE-4는 붕괴 조치를 취하겠다.","JPN":"現時刻をもって、LAKE-4は崩壊措置を取る。","ENG":"As of this moment, LAKE-4 will start its self-destruct sequence.","TWN":"從現在起，LAKE-4將啟動崩塌計畫。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"무너져 내린 산에서 파편을 발굴해내는 데 얼마나 걸릴지 기대되는군.","JPN":"崩れ落ちた山から破片を発掘するのにどれくらいの時間がかかるか楽しみだな。","ENG":"I'm wondering how long it will take them to excavate the Fragment when it's buried under the mountain.","TWN":"我很期待，在垮塌的山上挖掘碎片需要多長時間。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ELIZABETH_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"지, 지휘관님!","JPN":"し、指揮官！","ENG":"C-Commander!","TWN":"指…指揮官！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"ASSIST_NPC_ESPR2_NULL","text":{"KOREA":"큰일입니다! 폭발물들이 격발되지 않습니다!","JPN":"大変です！　爆発物が撃発できません！","ENG":"We have a situation! The explosives aren't detonating!","TWN":"不好了！爆炸物沒有被引爆！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"뭐? 그럴 리가!","JPN":"何だと？　そんなはずは！","ENG":"What?! That can't be!","TWN":"什麼？怎麼可能！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"붕괴 조치에 관련된 자료는 극비다! 이제까지 단 한 차례도 새어나간 적 없어!","JPN":"崩壊措置に関する資料は極秘だ！　今まで一度も漏れたことなどないんだぞ！","ENG":"The self-destruct sequence was top secret! It has never been leaked once!","TWN":"有關崩塌措施的資料是絕密！之前從來沒有洩露過！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ASSIST_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"이 놈들, 언제 통제실까지……?!","JPN":"こいつら、いつの間に統制室まで……！？","ENG":"Those bastards...! When did they reach the Control Room...?!","TWN":"這些傢伙，什麼時候掌控了控制室……？！"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"오우, 공기부터가 남다르네. 여기가 제일 중요한 곳인가 봐.","JPN":"わお、空気から違うね。ここが一番重要な場所？","ENG":"Ooh, this place looks different. Must be really important what happens here, no?","TWN":"噢噢，連空氣都不一樣呢。看來這裡就是最重要的地方了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"안녕, 친구들? 친절한 리벳 언니를 기다리느라 많이 지루했지?","JPN":"やあ、みんな。優しいリベット姉さんが来るの、待ちくたびれたでしょ？","ENG":"Hey there, pals! Were you getting tired of waiting for me, your friendly Ms. Rivet?","TWN":"你們好呀？一直等待親切的里維姊姊，應該很無聊吧？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래도 한창 재밌을 때에 무대를 터뜨리려고 하면 못 써.","JPN":"でもこんな盛り上がってる最中に舞台を爆発させようとしちゃダメだよ。","ENG":"But you can't blow up the stage when it is just about to get good!","TWN":"不過我正玩得開心呢，你們想要炸毀舞台可不行。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"너였군. 폭발물의 존재는 어떻게 알았지?","JPN":"お前だったんだな。爆発物の存在はどうやって知った？","ENG":"So it was you. How did you know about the explosives?","TWN":"原來是你。你是怎麼知道爆炸物的存在的？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"그림자들의 지원이 꽤나 유용했다오.","JPN":"シャドウの支援がずいぶんと役に立った。","ENG":"The support of the Shadows has been quite useful.","TWN":"暗影的支援相當有用。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"아랫사람들도 수상한 시설이 있다는 건 알고 있었소. 남은 건 확인뿐이었지.","JPN":"下の者たちも怪しい施設があるということは知っていたのだ。あとは確認するだけだった。","ENG":"Even my subordinates knew there was a suspicious facility here. We only needed confirmation.","TWN":"你手下的人也知道有可疑的設施。所以剩下的只要去確認就好。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"전투가 벌어지자마자 지체 없이 격발했다면 더 큰 피해를 입혔을 텐데, 망설임이 발목을 잡았군.","JPN":"戦闘が始まった瞬間撃発していれば、より大きな被害を与えることができただろうに。迷いが足手まといになったな。","ENG":"You would have done us a lot of damage if you had detonated it right away when the battle started. However, it appears that hesitation got in the way.","TWN":"如果戰鬥開始後你就立刻引爆的話，我們應該會蒙受很大損失，可惜你猶豫了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"COMMANDER_NPC_ESPR2_NULL","text":{"KOREA":"이런…… 융합체들까지 끌고 온 건가.","JPN":"まずい……融合体まで引き連れてきたのか。","ENG":"Damn... Did they bring hybriders?","TWN":"可惡……融合體也牽扯進來了嗎。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_NPC_ESPR2_NULL","face":"UNIT_IDLE"},"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"처음 뵙겠소. 생물학부장 하이드리히요.","JPN":"お初にお目にかかる。生物学部長のハイドリヒだ。","ENG":"A pleasure to meet you. I am Heydrich, Dean of Biology.","TWN":"初次見面，我是生物學院院長海德里希。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"BIO_NPC_ESPR2_NULL","text":{"KOREA":"간부급에게는 알아내야 할 지식이 많지. 투항하는 선택지도 있소만.","JPN":"幹部級からは引き出さねばならない知識が多い。投降するという選択肢もあるぞ。","ENG":"Officers have a lot of knowledge to give. May I recommend that you surrender?","TWN":"像你這樣的幹部，我們有很多要了解的東西。你還有選擇投降的機會。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"에이, 할아범. 그럼 섭섭하지.","JPN":"もう、お爺さんったら。つまらないこと言わないでよ。","ENG":"Oh, gramps. That's no fun at all!","TWN":"喂，老頭，你這麼說就掃興了。"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"이럴 때 안 쏘면 또 언제 쏘겠다는 거야?","JPN":"こういう時に撃たないで、いつ撃つっていうの？","ENG":"When do I get to shoot things?","TWN":"這個時候不開槍，還想什麼時候開槍啊？"},"stage":{"bg":"PROLOGUE_02","bgm":"THEMA_ESPR_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BIO_NPC_ESPR2_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"}]`);export{e as default};